def gen(rng, size):
    alpha = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789'
    chars = []
    n = rng.randint(0, max(1, size))
    for _ in range(n):
        if rng.random() < 0.3:
            chars.append(' ')
        else:
            chars.append(rng.choice(alpha))
    return [''.join(chars)]

