var countSegments = function(s) {
    let count = 0;
    let prevSpace = true;
    for (const ch of s) {
        if (ch !== ' ') {
            if (prevSpace) count++;
            prevSpace = false;
        } else {
            prevSpace = true;
        }
    }
    return count;
